INSERT INTO `posts` (`id`, `user_id`, `title`, `category`, `content`, `excerpt`, `image_url`, `status`, `views`, `created_at`, `updated_at`) VALUES
(4, 1, 'Giải trí cuối tuần: sự kiện âm nhạc học đường', 'Giải trí', 'Sự kiện âm nhạc cuối tuần là dịp để sinh viên thư giãn, gặp gỡ bạn bè và tham gia các hoạt động câu lạc bộ. Không gian mở giúp mọi người kết nối và lan tỏa năng lượng tích cực sau một tuần học tập.', 'Sự kiện âm nhạc giúp sinh viên kết nối và thư giãn.', 'https://images.unsplash.com/photo-1529911098878-0d82c7fb1c68?auto=format&fit=crop&w=1200&q=80', 'published', 0, '2026-03-24 19:00:00', '2026-04-13 11:14:28'),
(5, 1, 'Tuyển thủ thể thao và câu chuyện cảm hứng', 'Đời sống', 'Những buổi tập sớm, lịch học dày và áp lực thi đấu tạo nên hành trình không dễ dàng cho các tuyển thủ sinh viên. Từ nỗ lực đó, họ học được kỷ luật, tinh thần đồng đội và cách vượt qua giới hạn bản thân.', 'Câu chuyện nỗ lực của tuyển thủ thể thao sinh viên.', 'https://images.unsplash.com/photo-1508609349937-5ec4ae374ebf?auto=format&fit=crop&w=1200&q=80', 'published', 1, '2026-03-25 07:45:00', '2026-04-13 11:17:16'),
(6, 1, 'Khám phá lab Công nghệ mới của trường', 'Công nghệ', 'Phòng lab công nghệ mở ra nhiều cơ hội thực hành cho sinh viên với các chủ đề như lập trình web, dữ liệu, thiết kế giao diện và mô phỏng hệ thống. Đây là môi trường phù hợp để biến ý tưởng thành sản phẩm demo.', 'Không gian thực hành công nghệ dành cho sinh viên.', 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?auto=format&fit=crop&w=1200&q=80', 'published', 0, '2026-03-27 14:20:00', '2026-04-13 11:14:28'),
(7, 1, 'Chiến lược thi cuối kỳ hiệu quả', 'Học tập', 'Ôn thi hiệu quả không chỉ là học nhiều giờ, mà còn là biết chia nhỏ nội dung, tự kiểm tra kiến thức và nghỉ ngơi đúng lúc. Một kế hoạch rõ ràng giúp sinh viên giảm áp lực và cải thiện kết quả.', 'Cách lập kế hoạch ôn thi cuối kỳ khoa học.', 'https://images.unsplash.com/photo-1526470498-9a1e49fda1d4?auto=format&fit=crop&w=1200&q=80', 'published', 0, '2026-03-26 11:00:00', '2026-04-13 11:14:28'),
(8, 1, 'Hoạt động cộng đồng: chiến dịch Xanh trường học', 'Sự kiện', 'Chiến dịch Xanh trường học khuyến khích sinh viên tham gia thiết kế poster, dọn dẹp khuôn viên và truyền thông về lối sống bền vững. Những hoạt động nhỏ tạo nên thói quen tốt cho cộng đồng.', 'Sinh viên cùng tham gia chiến dịch bảo vệ môi trường.', 'https://images.unsplash.com/photo-1505404919724-80a98f7b38c9?auto=format&fit=crop&w=1200&q=80', 'published', 0, '2026-03-31 15:40:00', '2026-04-13 11:14:28'),
(10, 1, 'Khám phá công nghệ AI mới', 'Công nghệ', 'Công nghệ AI đang thay đổi cách chúng ta làm việc và học tập. Hãy cùng khám phá những xu hướng mới nhất trong lĩnh vực này.', 'Công nghệ AI đang thay đổi cách chúng ta làm việc và học tập. Hãy cùng khám phá những xu hướng mới nhất trong lĩnh vực này.', 'https://images.unsplash.com/photo-1677442d019cecf4d4dac7298cfc7b138ee50914a?auto=format&fit=crop&w=1200&q=80', 'published', 2, '2026-04-06 10:13:50', '2026-04-06 23:47:40'),
(11, 1, 'Bí quyết học tập hiệu quả', 'Học tập', 'Muốn cải thiện kết quả học tập? Hãy biết đến những phương pháp học tập khoa học được chứng minh hiệu quả.', 'Muốn cải thiện kết quả học tập? Hãy biết đến những phương pháp học tập khoa học được chứng minh hiệu quả.', 'https://images.unsplash.com/photo-1427504494785-cdedca239cc1?auto=format&fit=crop&w=1200&q=80', 'published', 0, '2026-04-06 10:13:50', '2026-04-06 10:13:50'),
(12, 1, 'Xu hướng thời trang mùa hè 2026', 'Đời sống', 'Mùa hè sắp đến, hãy cập nhật những xu hướng thời trang mới nhất cho mùa này.', 'Mùa hè sắp đến, hãy cập nhật những xu hướng thời trang mới nhất cho mùa này.', 'https://images.unsplash.com/photo-1595580677313-7dcbb8ce3fe7?auto=format&fit=crop&w=1200&q=80', 'published', 4, '2026-04-06 10:13:50', '2026-04-14 08:14:53'),
(13, 1, 'Cuộc thi Lập trình quốc gia', 'Sự kiện', 'Đây là cơ hội để các bạn sinh viên thể hiện tài năng lập trình của mình trong cuộc thi cấp quốc gia.', 'Đây là cơ hội để các bạn sinh viên thể hiện tài năng lập trình của mình trong cuộc thi cấp quốc gia.', 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?auto=format&fit=crop&w=1200&q=80', 'published', 2, '2026-04-06 10:13:50', '2026-04-14 09:10:23');
